/**
 * CLI brand icons — local SVG paths (from official/simple brand assets).
 *
 * Assets live in `src/assets/cli-icons/`. Components use `currentColor` so
 * parents can set theme / brand accent via CSS color.
 */

import type { ComponentType, ReactNode, SVGProps } from "react";
import type { KnownCliType } from "./cli-enablement";

export type CliIconProps = SVGProps<SVGSVGElement>;

function BrandIcon({
  title,
  viewBox = "0 0 24 24",
  children,
  className,
  ...rest
}: CliIconProps & { readonly title: string; readonly children: ReactNode }) {
  return (
    <svg
      aria-hidden="true"
      className={className ? `cli-brand-icon ${className}` : "cli-brand-icon"}
      fill="currentColor"
      fillRule="evenodd"
      viewBox={viewBox}
      xmlns="http://www.w3.org/2000/svg"
      {...rest}
    >
      <title>{title}</title>
      {children}
    </svg>
  );
}

/** Fallback for unknown / external CLI types. */
function FallbackCliIcon(props: CliIconProps) {
  return (
    <BrandIcon title="CLI" viewBox="0 0 20 20" {...props}>
      <rect x="3.3" y="4.1" width="13.4" height="11.8" rx="2" fill="none" stroke="currentColor" strokeWidth="1.35" />
      <path
        d="m6.2 7.4 2.2 2.1-2.2 2.1M9.7 12h3.7"
        fill="none"
        stroke="currentColor"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="1.35"
      />
    </BrandIcon>
  );
}

