/** Map of known CLI type → icon component. */
export const CLI_ICON_COMPONENTS: Readonly<Record<KnownCliType, ComponentType<CliIconProps>>> = {
  codex: CodexCliIcon,
  claude: ClaudeCliIcon,
  opencode: OpenCodeCliIcon,
  grok: GrokCliIcon,
  copilot: CopilotCliIcon,
  antigravity: AntigravityCliIcon,
  kiro: KiroCliIcon,
  cursor: CursorCliIcon,
  droid: DroidCliIcon,
};

/** Brand accent colors for CLI labels (icons use currentColor). */
export const CLI_BRAND_COLORS: Readonly<Record<KnownCliType, string>> = {
  codex: "#6366f1",
  claude: "#d97706",
  opencode: "#059669",
  grok: "#0f766e",
  copilot: "#2563eb",
  antigravity: "#7c3aed",
  kiro: "#dc2626",
  cursor: "#6b7280",
  droid: "#16a34a",
};

export function getCliBrandColor(cliType: string): string {
  if (cliType in CLI_BRAND_COLORS) {
    return CLI_BRAND_COLORS[cliType as KnownCliType];
  }
  return "currentColor";
}

/** Resolve a CLI icon component; falls back for unknown types. */
export function getCliIconComponent(cliType: string): ComponentType<CliIconProps> {
  if (cliType in CLI_ICON_COMPONENTS) {
    return CLI_ICON_COMPONENTS[cliType as KnownCliType];
  }
  return FallbackCliIcon;
}

/** Render the icon for a CLI type (safe for unknown types). */
export function CliBrandIcon({
  cliType,
  className,
  style,
  ...rest
}: CliIconProps & { readonly cliType: string }) {
  const Icon = getCliIconComponent(cliType);
  return <Icon className={className} style={style} {...rest} />;
}
